package com.nattechnologies.trastcms.plugins.saas; import jakarta.persistence.*; import java.time.Instant; import java.util.UUID;
@Entity @Table(name="saas_license") class SaasLicense{@Id@Column(length=36)String id;@ManyToOne(fetch=FetchType.LAZY,optional=false)@JoinColumn(name="product_id")SaasProduct product;@ManyToOne(fetch=FetchType.LAZY,optional=false)@JoinColumn(name="plan_id")SaasPlan plan;@ManyToOne(fetch=FetchType.LAZY)@JoinColumn(name="subscription_id")SaasSubscription subscription;@Column(name="customer_email",nullable=false,length=190)String customerEmail;@Column(name="order_id",length=36)String orderId;@Column(name="key_hash",nullable=false,unique=true,length=64)String keyHash;@Lob@Column(name="key_cipher",nullable=false)String keyCipher;@Column(name="key_prefix",nullable=false,length=20)String keyPrefix;@Enumerated(EnumType.STRING)@Column(nullable=false,length=30)LicenseStatus status=LicenseStatus.ACTIVE;@Column(name="max_activations",nullable=false)int maxActivations=1;@Column(name="issued_at",nullable=false)Instant issuedAt;@Column(name="expires_at")Instant expiresAt;@Column(name="grace_ends_at")Instant graceEndsAt;@Column(name="last_validated_at")Instant lastValidatedAt;@Column(name="created_at",nullable=false)Instant createdAt;@PrePersist void create(){if(id==null)id=UUID.randomUUID().toString();createdAt=Instant.now();}}
